    pub fn parse_ws_balance(&self, mut balance: Value, optional_args: &[Value]) {
        let mut accountType = get_arg(optional_args, 0, Value::Null);
        //
        // spot
        //
        //     {
        //         "margin_market": "BTCUSDT",
        //         "ccy": "BTC",
        //         "available": "44.62207740",
        //         "frozen": "0.00000000",
        //         "updated_at": 1689152421692
        //     }
        //
        // swap
        //
        //     {
        //         "ccy": "USDT",
        //         "available": "97.92470982756335000001",
        //         "frozen": "0.00000000000000000000",
        //         "margin": "0.61442700000000000000",
        //         "transferrable": "97.92470982756335000001",
        //         "unrealized_pnl": "-0.00807000000000000000",
        //         "equity": "97.92470982756335000001"
        //     }
        //
        let mut account: Value = self.account();
        let mut currencyId: Value = self.safe_string_k(balance.clone(), "ccy", &[]);
        let mut code: Value = self.safe_currency_code(currencyId.clone(), &[]);
        add_element_to_object(&mut account, &Value::Str("free".to_string()), self.safe_string_k(balance.clone(), "available", &[]));
        add_element_to_object(&mut account, &Value::Str("used".to_string()), self.safe_string_k(balance.clone(), "frozen", &[]));
        if !is_equal(&accountType, &Value::Null) {
            if is_equal(&self.safe_value(self.balance.clone(), accountType.clone(), &[]), &Value::Null) {
                add_element_to_object(&mut self.balance.clone(), &accountType, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
            }
            add_element_to_object(get_value_mut(unsafe { crate::runtime::coerce_value_to_mut(&self.balance) }, &accountType), &code, account.clone());
        }  else {
            add_element_to_object(&mut self.balance.clone(), &code, account.clone());
        }
}

